    }
    dp[0][0][0] = 0;

    for (let t = 0; t <= k; t++) {
        if (t > 0) {
            const minCost = new Array(maxVal+1).fill(Number.MAX_SAFE_INTEGER);
            for (let i = 0; i < m; i++) {
                for (let j = 0; j < n; j++) {
                    if (dp[t-1][i][j] === Number.MAX_SAFE_INTEGER) continue;
                    const val = grid[i][j];
                    if (dp[t-1][i][j] < minCost[val]) {
